# File signature (magic bytes) database
FILE_SIGNATURES = {
    b'\xff\xd8\xff': ('JPEG image', '.jpg'),
    b'\x89PNG': ('PNG image', '.png'),
    b'%PDF': ('PDF document', '.pdf'),
    b'PK\x03\x04': ('ZIP archive', '.zip'),
    b'\x7fELF': ('Linux executable', '.elf'),
    b'MZ': ('Windows executable', '.exe'),
    b'GIF8': ('GIF image', '.gif'),
    b'\x1f\x8b': ('GZIP archive', '.gz'),
}

def identify_file(filepath):
    with open(filepath, 'rb') as f:
        header = f.read(8)
    for sig, (name, ext) in FILE_SIGNATURES.items():
        if header[:len(sig)] == sig:
            return {'type': name, 'extension': ext, 'signature': sig.hex()}
    return {'type': 'Unknown', 'extension': '', 'signature': header[:4].hex()}

