import base64
import binascii

def analyse_encoding(data):
    results = []
    # Try Base64
    try:
        decoded = base64.b64decode(data)
        if decoded.isascii() or len(decoded) > 0:
            results.append(('Base64', decoded))
    except Exception:
        pass
    # Try Hex
    try:
        decoded = binascii.unhexlify(data)
        if decoded.isascii():
            results.append(('Hex', decoded))
    except Exception:
        pass
    # Check if already plaintext
    if isinstance(data, str) and data.isprintable():
        results.append(('Plaintext', data.encode()))
    return results

