import base64
import re

def find_base64(text):
    pattern = r'[A-Za-z0-9+/]{20,}={0,2}'
    candidates = re.findall(pattern, text)
    results = []
    for candidate in candidates:
        try:
            decoded = base64.b64decode(candidate)
            try:
                text_decoded = decoded.decode('utf-8')
                results.append({'encoded': candidate[:30]+'...', 'decoded': text_decoded, 'type': 'text'})
            except UnicodeDecodeError:
                results.append({'encoded': candidate[:30]+'...', 'decoded': f'<binary {len(decoded)} bytes>', 'type': 'binary'})
        except Exception:
            pass
    return results

