def text_to_bits(text):
    return ''.join(format(ord(c),'08b') for c in text) + '00000000'  # Null terminator

def bits_to_text(bits):
    chars = []
    for i in range(0, len(bits), 8):
        byte = bits[i:i+8]
        if len(byte) == 8:
            c = chr(int(byte, 2))
            if c == '\x00': break
            chars.append(c)
    return ''.join(chars)

def hide_message(pixels, message):
    bits = text_to_bits(message)
    if len(bits) > len(pixels):
        raise ValueError(f'Message too long ({len(bits)} bits > {len(pixels)} pixels)')
    stego = list(pixels)
    for i, bit in enumerate(bits):
        stego[i] = (stego[i] & 0xFE) | int(bit)
    return stego

def extract_message(pixels):
    bits = ''.join(str(p & 1) for p in pixels)
    return bits_to_text(bits)

def detect_stego(original, suspect):
    diffs = sum(1 for a, b in zip(original, suspect) if a != b)
    pct = diffs / len(original) * 100
    return {'modified_pixels': diffs, 'percentage': pct, 'suspicious': pct > 1}

