def xor_decode(data, key):
    return bytes([b ^ key for b in data])

def english_score(text):
    freq = 'etaoinshrdlcumwfgypbvkjxqz '
    return sum(1 for c in text.lower() if c in freq)

def crack_single_xor(ciphertext):
    best = {'key':0, 'score':0, 'text':''}
    for key in range(256):
        decoded = xor_decode(ciphertext, key)
        try:
            text = decoded.decode('ascii', errors='ignore')
            score = english_score(text)
            if score > best['score']:
                best = {'key':key, 'score':score, 'text':text}
        except:
            pass
    return best

