import os
from datetime import datetime

def analyse_directory(directory):
    files = []
    for root, dirs, filenames in os.walk(directory):
        for fname in filenames:
            fpath = os.path.join(root, fname)
            try:
                stat = os.stat(fpath)
                files.append({
                    'name': fname, 'path': fpath,
                    'size': stat.st_size,
                    'modified': datetime.fromtimestamp(stat.st_mtime),
                    'ext': os.path.splitext(fname)[1].lower()
                })
            except: pass

    print(f'=== DIRECTORY ANALYSIS: {directory} ===')
    print(f'Files: {len(files)}')
    total = sum(f['size'] for f in files)
    print(f'Total size: {total:,} bytes')

    # Detect anomalies
    anomalies = []
    for f in files:
        if f['name'].startswith('.'): anomalies.append(f'Hidden file: {f["name"]}')
        if f['size'] == 0: anomalies.append(f'Empty file: {f["name"]}')
        if f['ext'] in ['.exe','.bat','.ps1','.vbs']:
            anomalies.append(f'Executable: {f["name"]}')
        if f['size'] > 10_000_000:
            anomalies.append(f'Large file ({f["size"]/1_000_000:.1f}MB): {f["name"]}')

    if anomalies:
        print(f'\n🚨 ANOMALIES ({len(anomalies)}):')
        for a in anomalies: print(f'  ⚠️ {a}')
    else:
        print('\n✅ No anomalies detected')
    return files

